package com.example.yourappname

import android.content.Context
import android.content.SharedPreferences

class AuthManager(private val context: Context) {

    private val sharedPrefs: SharedPreferences by lazy {
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
    }

    // Data class to hold authenticated user information
    data class AuthData(
        val userId: String,
        val authToken: String
    )

    // Saves the user's authentication data
    fun saveAuthData(userId: String, authToken: String) {
        sharedPrefs.edit().apply {
            putString(KEY_USER_ID, userId)
            putString(KEY_AUTH_TOKEN, authToken)
            apply() // Use apply for asynchronous save, commit for synchronous
        }
    }

    // Retrieves the user's authentication data
    fun getAuthData(): AuthData? {
        val userId = sharedPrefs.getString(KEY_USER_ID, null)
        val authToken = sharedPrefs.getString(KEY_AUTH_TOKEN, null)

        return if (!userId.isNullOrEmpty() && !authToken.isNullOrEmpty()) {
            AuthData(userId, authToken)
        } else {
            null
        }
    }

    // Clears all stored authentication data, effectively logging out the user
    fun clearAuthData() {
        sharedPrefs.edit().apply {
            remove(KEY_USER_ID)
            remove(KEY_AUTH_TOKEN)
            apply()
        }
    }

    // Checks if a user is currently logged in
    fun isLoggedIn(): Boolean {
        return getAuthData() != null
    }

    companion object {
        private const val PREFS_NAME = "auth_prefs"
        private const val KEY_USER_ID = "user_id"
        private const val KEY_AUTH_TOKEN = "auth_token"
    }
}